python3 - <<'EOF'
import re

with open('/Users/jhoetter/repos/bim-ai/spec/revit-parity/revit2026-parity-tracker.md') as f:
    content = f.read()

# Map chapters to WPs
wp_chapters = {
    'WP-A': [4, 5, 6],
    'WP-B': [3, 2],
    'WP-C': [8, 2, 3],
    'WP-D': [6, 1, 3],
    'WP-E': [12, 13],
    'WP-F': [2, 1],
    'WP-G': [9, 11, 8],
}

# Count statuses per chapter
chapter_pattern = re.compile(r'## Chapter (\d+)')
status_pattern = re.compile(r'- .+?: (Done|Partial|Not Started)', re.IGNORECASE)

lines = content.split('\n')
current_chapter = None
chapter_stats = {}

for line in lines:
    ch_match = chapter_pattern.match(line)
    if ch_match:
        current_chapter = int(ch_match.group(1))
        if current_chapter not in chapter_stats:
            chapter_stats[current_chapter] = {'Done': 0, 'Partial': 0, 'Not Started': 0}
    if current_chapter:
        for status in ['Done', 'Partial', 'Not Started']:
            if f': {status}' in line or f'— {status}' in line:
                chapter_stats[current_chapter][status] = chapter_stats[current_chapter].get(status, 0) + 1

# Print by WP
for wp, chapters in wp_chapters.items():
    totals = {'Done': 0, 'Partial': 0, 'Not Started': 0}
    for ch in set(chapters):
        stats = chapter_stats.get(ch, {})
        for k in totals:
            totals[k] += stats.get(k, 0)
    total = sum(totals.values())
    print(f"{wp} (ch {chapters}): Done={totals['Done']} Partial={totals['Partial']} NotStarted={totals['Not Started']} / {total}")
EOF

